// On boucle sur tous les éléments entrants (généralement un seul depuis Ollama)
for (const item of $input.all()) {
  let sqlQuery = item.json.text;

  // 1. Sécurité anti-markdown
  sqlQuery = sqlQuery.replace(/```sql|```/gi, '').trim();

  // 2. Remplacement des "\n" textuels et des vrais retours à la ligne par des espaces
  sqlQuery = sqlQuery.replace(/\\n/g, ' ').replace(/\n/g, ' ');

  // 3. Nettoyage des espaces multiples pour que la requête soit propre
  sqlQuery = sqlQuery.replace(/\s+/g, ' ').trim();

  // On injecte le résultat final
  item.json.query_sql = sqlQuery;
}

return $input.all();
